What could be the problem? Have I missed any settings or is it a bug in the module itself?

The network topology diagram is like this：
_Client Machine C --> Nginx Machine B（installed connect_module）--> Nginx Machine A（installed connect_module）  --> target website_

Machine A can access the external network，Machine B can access Machine A，Machine C can access Machine B，How to configure make Machine C can access https website？I tried this configuration，Machine C can access http website，but cannot access https website。

```
# Machine A configuration，After this，Machine B can access http/https website
server {
	listen  8080;

	# dns resolver used by forward proxying
	resolver  114.114.114.114;

	# forward proxy for CONNECT request
	proxy_connect;
	proxy_connect_allow            443 80;
	proxy_connect_connect_timeout  10s;
	proxy_connect_read_timeout     10s;
	proxy_connect_send_timeout     10s;

	# forward proxy for non-CONNECT request
	location / {
		proxy_pass $scheme://$host;
		proxy_set_header Host $host;
	}
}
```

```
# Machine B configuration，After this，Machine C can access http website
server {
	listen                           8081;
	#server_name                     localhost;
	#resolver                        Machine A ipv6=off;
        #proxy_connect;
	#proxy_connect_allow            443 80;
	#proxy_connect_connect_timeout  10s;
	#proxy_connect_read_timeout     10s;
	#proxy_connect_send_timeout     10s;
	location / {
		proxy_pass $scheme://Machine A:8081;
		proxy_set_header Host $host;
		proxy_set_header Referer $http_referer;    
		proxy_set_header X-Real-IP $remote_addr;
		proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
		proxy_set_header X-Forwarded-Proto $scheme;
	}
}
```

I have tried multiple configuration methods in Machine B，still cannot make Machine C access https website，can you tell me where I went wrong？

is it possible to use the rate limiting functionality of nginx with this module?

Using the following config, I am able to successfully rate limit `http` requests, but anything connecting to `https` appears to be unlimited.  So it would seem that the `CONNECT` requests are not limited at all.  Is there a way to achieve this?  My suspicion is that this is expected, but I would like to confirm before I have to try to find another solution.

```
http {
    include       /etc/nginx/mime.types;
    default_type  application/octet-stream;

    log_format  main  '$remote_addr - $remote_user [$time_local] "$request" '
                      '$status $body_bytes_sent "$http_referer" '
                      '"$http_user_agent" "$http_x_forwarded_for"';

    access_log  /var/log/nginx/access.log  main;

    sendfile        on;
    #tcp_nopush     on;

    keepalive_timeout  65;

    #gzip  on;

    limit_req_zone $host zone=images:10m rate=1r/m;

    server {
        listen 8080;

        resolver 1.1.1.1 ipv6=off;

        # forward proxy for CONNECT requests
        proxy_connect;
        proxy_connect_allow            443;
        proxy_connect_connect_timeout  10s;
        proxy_connect_data_timeout     10s;

        location / {
            limit_req zone=images;

            proxy_pass http://$host;
            proxy_set_header Host $host;
        }
    }
}
```
